-- ============================================
-- V41: graph-rag-planner 模板支持 query intent
-- 新增 {intent} 占位符，让 Planner 根据意图类型（FACT_LOOKUP / COMPARATIVE等）调整查询策略
-- ============================================

UPDATE lg_prompt_template
SET task_prompt = E'## 用户问题\n{question}\n\n## 查询意图\n{intent}\n\n## 相关 Claim（知识断言）\n{claims}\n\n## 规划要求\n\n1. **拆分子问题**：将用户问题拆分为 2-5 个可独立查询的子问题（subQuestions），按优先级排列。每个 subQuestion 包含：targetType（Feature/ApiEndpoint/Table/BusinessRule 等）、具体的 query 描述、priority（HIGH/MEDIUM/LOW）。\n2. **Claim 过滤**：设计 ClaimQuery 列表，每条指定 subjectType、predicate、sourceType、minConfidence 等过滤条件。\n3. **路径查询**：设计 PathQuery 列表，每条指定 startNodeType（起始节点类型）、relationshipPattern（边类型序列，如 CALLS|HANDLED_BY|READS）、endNodeType（目标节点类型）、pathDepth（最大跳数 1-5）。\n4. **证据类型**：列出回答问题所需的证据类型：CLAIM（知识断言）、CODE_AST（代码 AST）、TABLE_SCHEMA（表结构）、API_DOC（接口文档）、TRACE（运行时链路）、TEST_RESULT（测试结果）、MANUAL_REVIEW（人工审核）。\n\n## 按意图调整策略\n- FACT_LOOKUP：查询具体事实（方法签名、参数类型、表结构），侧重 Claim（subjectType=Method/Table/ApiEndpoint），pathDepth=1。\n- STRUCTURAL：查询系统结构（模块依赖、分层关系），侧重 PathQuery（Feature→API→Service→Table），pathDepth=2-4。\n- RELATIONAL：查询实体间关系（调用链、数据流），侧重 PathQuery + Claim，pathDepth=2-3。\n- COMPARATIVE：对比版本差异——如有多个版本的 Claim，分别查询各自的 subjectKey，标注 versionId；若无多版本数据，用当前版本的结构化信息做对比。\n\n## 规则\n1. 不得编造系统中不存在的接口、表、方法、业务对象。\n2. 如果输入中的 Claim 不足以回答用户问题，设为 needsHumanReview=true 并说明原因。\n3. 优先级排序：先查 Feature 入口（EXPOSED_BY）→ 再查 API 实现（HANDLED_BY/CALLS）→ 再查数据路径（READS/WRITES）→ 最后查规则/权限。\n4. 使用中文输出 reasoning 和所有描述性字段。\n\n## 输出格式\n{\n  "subQuestions": [{"targetType": "ApiEndpoint", "query": "...", "priority": "HIGH", "dependsOn": -1}],\n  "claimQueries": [{"subjectType": "ApiEndpoint", "predicate": "HANDLED_BY", "sourceType": null, "minConfidence": 0.5}],\n  "pathQueries": [{"startNodeType": "Feature", "relationshipPattern": "EXPOSED_BY|HANDLED_BY|READS", "endNodeType": "Table", "pathDepth": 3}],\n  "requiredEvidenceTypes": ["CLAIM", "TABLE_SCHEMA"],\n  "reasoning": "先找到Feature→API入口，再沿调用链找到直接读写的数据表",\n  "needsHumanReview": false\n}'
WHERE template_code = 'graph-rag-planner' AND is_active = TRUE;
